import React from "react";
import Post2 from "../../assets/images/DashboardImgs/post-2.png";
import ApiRequest from "../../Services/ApiRequest";
import { toasterAlert } from "../../Helpers/Functions";
import { Link } from "react-router-dom";



class CompanyInfoTab extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            errors: {},
        };
        this.handleChange = this.handleChange.bind(this);
        this.handleSubmit = this.handleSubmit.bind(this);

    }
    componentDidMount() {
        window.scrollTo(0, 0)
    }

    handleChange = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        })
    }
    handleSubmit = async (event) => {
        event.preventDefault();
        const { name, company_name, phone_no, company_size, hear_about_us_id } = this.state;
        let { nameError, companyNameError, phoneError, companySizeError, aboutUsError } = '';
        if (!name) {
            nameError = "This field is required";
        }
        if (!company_name) {
            companyNameError = "This field is required";
        }
        if (!phone_no) {
            phoneError = "This field is required";
        }
        if (!company_size) {
            companySizeError = "This field is required";
        }
        if (!hear_about_us_id) {
            aboutUsError = "This field is required";
        }
        // const errors = {cityError, companyNameError, hiringBudgetError, howManyHiresError, jobTitleError, userRoleError};
        this.setState({
            errors: {
                nameError: nameError,
                companyNameError: companyNameError,
                phoneError: phoneError,
                companySizeError: companySizeError,
                aboutUsError: aboutUsError,
            }
        })

        if (nameError || companyNameError || phoneError || companySizeError || aboutUsError) {
            return;
        }
        const postData = JSON.parse(localStorage.getItem('postData'));
        const post_id = postData.jobPost.id;
        const response = await ApiRequest.postRequest('/jobPostCompanyInfo', { company_size, hear_about_us_id, name, company_name, phone_no, post_id:post_id })
        if (response && response.status === 200) {
            localStorage.setItem('companyInfo',  JSON.stringify(response.data));
            this.props.handler('step_three', true, response.data)
        } else {
            toasterAlert('error', 'Something went wrong please try again')
        }

    }
    render() {
        return (
            <div className={`row mar-width-0 postBodyWrap ${this.props.className}`}>
                <div className="container">
                    <div className="row mar-width-0 postWrap">
                        <div className="col-md-6 align-self-center pl-50">
                            <h3>Company Information</h3>
                        </div>
                        <div className="col-md-6 text-center pl-50">
                            <img src={Post2} alt="" />
                        </div>
                    </div>
                    <form className="w-100 form-wrap" onSubmit={this.handleSubmit}>
                        <div className="row mar-width-0 postDetails">
                            <div className="col-md-12">
                                <h5>Account info</h5>
                            </div>

                            <div className="col-md-12 mb-3">
                                <div className="form-group mb-0">
                                    <label htmlFor="exampleInputEmail1">Your name *</label>
                                    <input type="text" name="name" className="form-control" id="exampleInputEmail1"
                                    onChange={this.handleChange}
                                    value={this.state.name}
                                    />
                                    <span className="error">{this.state.errors.nameError}</span>
                                </div>
                            </div>

                            <div className="col-md-12 mb-3">
                                <div className="form-group mb-0">
                                    <label htmlFor="exampleInputEmail1">Your company name *</label>
                                    <input type="text" name="company_name" className="form-control" id="exampleInputEmail1"
                                    onChange={this.handleChange}
                                    value={this.state.company_name}
                                    />
                                    <span className="error">{this.state.errors.companyNameError}</span>

                                </div>
                            </div>

                            <div className="col-md-12 mb-3">
                                <div className="form-group mb-0">
                                    <label htmlFor="exampleInputEmail1">Phone number *</label>
                                    <input type="text" name="phone_no" className="form-control" id="exampleInputEmail1"
                                    onChange={this.handleChange}
                                    value={this.state.phone_no}
                                    />
                                    <span className="error">{this.state.errors.phoneError}</span>

                                </div>
                            </div>


                        </div>
                        <div className="row mar-width-0 postDetails">
                            <div className="col-md-12">
                                <h5>Company info</h5>
                            </div>
                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">Company size</label>
                                <select className="form-select" name="company_size" onChange={this.handleChange} value={this.state.company_size} aria-label="Default select example">
                                    <option selected></option>
                                    <option value="1">One</option>
                                    <option value="2">Two</option>
                                    <option value="3">Three</option>
                                </select>
                                <span className="error">{this.state.errors.companySizeError}</span>

                            </div>

                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">How did you hear about us?</label>
                                <select className="form-select" name="hear_about_us_id" onChange={this.handleChange} value={this.state.hear_about_us_id} aria-label="Default select example">
                                    <option selected></option>
                                    <option value="1">One</option>
                                    <option value="2">Two</option>
                                    <option value="3">Three</option>
                                </select>
                                <span className="error">{this.state.errors.aboutUsError}</span>

                            </div>

                            <div className="row mar-width-0 mt-5">
                                <div className="col-md-6">
                                    <Link to="/JobPosting" className="btn btn-back">Back</Link>

                                </div>
                                <div className="col-md-6 text-right">
                                    <button type="submit" className="btn btn-continue">Continue</button>
                                </div>
                            </div>

                        </div>
                    </form>
                </div>
            </div>
        )
    }
}

export default CompanyInfoTab;