import React from 'react';
import './postjob.css';
import Sidebar from "../../Components/Layouts/DashboardLayout/Sidebar";
import HeaderDashboard from "../../Components/Layouts/DashboardLayout/HeaderDashboard";
import { Link } from "react-router-dom";
import DLogo from "../../assets/images/DashboardImgs/dashboard-logo.png";
import PostJobTab from './PostJobTab';
import CompanyInfoTab from "./CompanyInfoTab";
import JobDetails from './JobDetails';
import ApiRequest from '../../Services/ApiRequest';
import PropTypes from 'prop-types';
import { RouteGuard } from '../../Services/RouteGuard';


class PostJob extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            step_one:true,
            step_two:false,
            step_three:false,
            personalInfo: [],
            countries: [],
            postDetail:[],
            languages:[],
            hiringRoles:[],
            hiringBudget:[]
        }
        this.handler = this.handler.bind(this)
    }

    handler(value, status, response=null) {
        if(status){
            const btn = ['step_one', 'step_two', 'step_three']
            if (!this.state[`${value}`]) {
                this.setState({
                    [`${value}`]: !this.state[`${value}`]
                })
            }
            btn.map((key) => {
                if (key !== value) {
                    this.setState({
                        [key]: false
                    })
                }
            })
        }
    }

    async componentDidMount() {
        RouteGuard('PostJob');
        
        const response = await ApiRequest.getRequest('/mentorPersonalInfo')
        if (response && response.status === 200 && response.data.personalInfo) {
            this.setState({
                personalInfo: response.data.personalInfo,
            })
        }

        // Get Countries
        const getCountries = await ApiRequest.getRequest('/getCountries');
        if (getCountries && getCountries.data.countries && getCountries.status === 200) {
            this.setState({
                countries: getCountries.data.countries
            })
        }

        // Get Languages
        const getlang = await ApiRequest.getRequest('/getLanguages');
        if (getlang && getlang.data.languages && getlang.status === 200) {
            this.setState({
                languages: getlang.data.languages
            })
        }

        // Get Hiring Roles
        const getRoles = await ApiRequest.getRequest('/getHiringRoles');
        if (getRoles && getRoles.data.hiringRoles && getRoles.status === 200) {
            this.setState({
                languages: getRoles.data.hiringRoles
            })
        }

        // Get Hiring Budget
        const getbudget = await ApiRequest.getRequest('/getHiringBudget');
        if (getbudget && getbudget.data.hiringBudget && getbudget.status === 200) {
            this.setState({
                languages: getbudget.data.hiringBudget
            })
        }

    }
    onclick = () => {
        alert();
    }
    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className="row mar-width-0 header-alter">
                    <div className="col-md-12">
                        <Link to="#" className="brand-logo">
                            <img src={DLogo} className="d-logo" alt="" />
                        </Link>
                    </div>
                </div>
                <PostJobTab className={!this.state.step_one?'d-none':''} handler={this.handler} personalInfo={this.state.personalInfo} countries={this.state.countries} languages={this.state.languages} hiringRoles={this.state.hiringRoles} hiringBudget={this.state.hiringBudget} />
                <CompanyInfoTab className={!this.state.step_two?'d-none':''} handler={this.handler} postDetail={this.state.postDetail} />
                <JobDetails className={!this.state.step_three?'d-none':''} handler={this.handler}/>
            </div>
        )
    }
}
// PostJob.propTypes = {
//     userInfo: PropTypes.element.isRequired,
//     countries: PropTypes.element.isRequired,
//   };
export default PostJob;

