import React from "react";
import Post1 from "../../assets/images/DashboardImgs/post-1.png";
import Pencil from "../../assets/images/DashboardImgs/pencil.png";
import ApiRequest from "../../Services/ApiRequest";
import Select from 'react-select';
import { countryCities } from "../../Helpers/Functions";
import PropTypes from 'prop-types';
import { toasterAlert } from "../../Helpers/Functions";
import { Link } from "react-router-dom";


class PostJobTab extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            errors: {},
            how_many_hires: 1,
            always_hiring: 0,
            personalInfo: {},
            country: {},
            countryEdit: false,
            cities: [],
            languageEdit: false,
            personalInfo: [],
            countries: [],
            citySelected: {},
            countrySelected: {},
            post_id: '',
            langSelected: {},
            langList: [],
            hiringRoles: [],
            hiringBudget: [],
        };
        this.handleChange = this.handleChange.bind(this);
        this.handleSubmit = this.handleSubmit.bind(this);

    }
    async componentDidMount() {
        // Post data
        const postData = JSON.parse(localStorage.getItem('postData'))
        console.log(postData)
        const citySelected = JSON.parse(localStorage.getItem('citySelected'))
        const countrySelected = JSON.parse(localStorage.getItem('countrySelected'))
        const langSelected = JSON.parse(localStorage.getItem('langSelected'))


        // props
        if (this.props?.personalInfo) {
            this.getCountryCities(this.props?.personalInfo[0]?.country?.id)
            this.setState({
                personalInfo: this.props?.personalInfo,
                country_id: this.props?.personalInfo[0]?.country?.id,
                post_lang_id: 1
            })
        }
        // Get Countries
        if (this.props?.countries) {
            this.setState({
                countries: this.props?.countries
            })
        }

        // get Languages Lists
        const getLang = await ApiRequest.getRequest('/getLanguages');
        if (getLang && getLang.status === 200) {
            this.setState({
                langList: getLang.data.languages
            })
        }

        // Get Hiring Roles
        const getRoles = await ApiRequest.getRequest('/getHiringRoles');
        if (getRoles && getRoles.data.hiringRoles && getRoles.status === 200) {
            this.setState({
                hiringRoles: getRoles.data.hiringRoles
            })
        }

        // Get Hiring Budget
        const getbudget = await ApiRequest.getRequest('/getHiringBudget');
        if (getbudget && getbudget.data.hiringBudget && getbudget.status === 200) {
            this.setState({
                hiringBudget: getbudget.data.hiringBudget
            })
        }

        if (postData && postData.status == 200) {
            this.setState({ citySelected, countrySelected, langSelected, country_id: countrySelected?.value })
            for (const [key, value] of Object.entries(postData.jobPost)) {
                if (key !== 'user_id' && key !== 'id') {
                    this.setState({
                        [key]: value
                    })
                }
                if (key === 'id') {
                    this.setState({
                        post_id: value
                    })
                }
            }

        }
    }
    countryEdit = () => {
        this.setState({
            countryEdit: !this.state.countryEdit
        })
    }
    countryDetails = () => {
        if (this.state.countryEdit && this.state.countrySelected) {
            if (this.props?.countries) {
                let options = [];
                this.props?.countries?.map(el => {
                    let arr = {
                        value: el.id,
                        label: el.name,
                    }
                    options.push(arr);
                });
                return (
                    <>
                        <label>Country</label>
                        <Select options={options} name="country_id" value={this.state.countrySelected} onChange={(e) => this.onChangeCountry(e)} />
                    </>
                )
            }
        } else {
            return (
                <label> Country: <span className="f-f">{this.props?.personalInfo[0]?.country?.name}<img src={Pencil} onClick={() => this.countryEdit()} className="pencil-icon cursor-pointer" alt="" /></span>
                </label>
            )
        }

        // if (!this.state.countryEdit && !this.state.countrySelected) {
        //     if (this.state.personalInfo.length == 1) {
        //         return (
        //             <label> Country: <span className="f-f">{this.state.personalInfo[0].country.name}<img src={Pencil} onClick={() => this.countryEdit()} className="pencil-icon cursor-pointer" alt="" /></span>
        //             </label>
        //         )
        //     }
        // } else {
        //     let options = [];
        //     this.state.countries.map(el => {
        //         let arr = {
        //             value: el.id,
        //             label: el.name,
        //         }
        //         options.push(arr);
        //     });
        //     return (
        //         <>
        //             <label>Country</label>
        //             <Select options={options} name="country_id" value={this.state.countrySelected} onChange={(e) => this.onChangeCountry(e)} />
        //         </>
        //     )

        // }
    }
    onChangeCountry = (event) => {
        const { value, label } = event;
        this.setState({
            country_id: value,
            countrySelected: {
                value: value,
                label: label
            }
        })
        this.getCountryCities(value);
    }
    OnChangeCity = (event) => {
        const { value, label } = event;
        this.setState({
            city_id: value,
            citySelected: {
                value: value,
                label: label
            }
        })
    }
    getCountryCities = async (id) => {
        if (id !== undefined && this.state.cities.length === 0) {
            const response = await ApiRequest.getRequest(`/getCountryCities/${id}`);
            if (response && response.status == 200) {
                this.setState({
                    cities: response.data.cities,
                    country_id: id,
                    countrySelected: {
                        value: this.props.personalInfo?.[0]?.country?.id,
                        label: this.props.personalInfo?.[0]?.country?.name,
                    }
                })
            }
        }
    }

    CitiesByCountry = () => {
        let options = [];
        if (this.state.cities) {
            this.state.cities.map(el => {
                let arr = {
                    value: el.id,
                    label: el.name,
                }
                options.push(arr);
            });
        }
        return (
            <Select options={options} value={this.state.citySelected} name="city_id" onChange={(e) => this.OnChangeCity(e)} />
        )

    }
    OnEditLanguage = () => {
        this.setState({
            languageEdit: !this.state.languageEdit
        })
    }
    OnChangeLang = (event) => {
        const { value, label } = event;
        this.setState({
            post_lang_id: value,
            langSelected: {
                value: value,
                label: label
            }
        })
    }
    LanguageList = () => {
        let options = [];
        if (this.state.langList) {
            this.state.langList.map(el => {
                console.log('langList ' + el)
                let arr = {
                    value: el.id,
                    label: el.lang_name,
                }
                options.push(arr);
            });
        }
        return (
            <>
                <label>Language</label>
                <Select options={options} value={this.state.langSelected} name="post_lang_id" onChange={(e) => this.OnChangeLang(e)} />
            </>

        )
    }
    hiringRolesList = () => {
        if (this.state.hiringRoles) {
            return (
                <select className="form-select" aria-label="Default select example" name="user_role_id" value={this.state.user_role_id} onChange={this.handleChange}>
                    <option>Select Roles</option>
                    {
                        this.state.hiringRoles.map(el => {
                            return (
                                <option value={el.id} key={el.id}>{el.role_name}</option>

                            )
                        })
                    }
                </select>

            )
        }
    }
    hiringBudgetList = () => {
        if (this.state.hiringBudget) {
            return (
                <select className="form-select" aria-label="Default select example" name="hiring_budget" value={this.state.hiring_budget} onChange={this.handleChange}>
                    <option>Select Roles</option>
                    {
                        this.state.hiringBudget.map(el => {
                            return (
                                <option value={el.id}>{el.start_price} - {el.end_price}</option>

                            )
                        })
                    }
                </select>

            )
        }
    }
    HiresAddUp = () => {
        this.setState({
            how_many_hires: ++this.state.how_many_hires
        })
    }
    HiresMinus = () => {
        let num = this.state.how_many_hires
        if (num > 1) {
            this.setState({
                how_many_hires: --this.state.how_many_hires
            })
        }
    }
    HandleCountryEdit = () => {

    }
    handleCheckbox = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: !this.state[name]
        })
    }

    handleChange(event) {
        const { name, value } = event.target;
        this.setState({ [name]: value })
    }

    handleSubmit = async (event) => {
        event.preventDefault();
        const { city_id, company_name, hiring_budget, how_many_hires, job_title, user_role_id, job_working_type, post_lang_id, country_id, always_hiring } = this.state;
        let { cityError, companyNameError, hiringBudgetError, howManyHiresError, jobTitleError, userRoleError, JobWorkTypeError } = '';
        if (!city_id) {
            cityError = "This field is required";
        }
        if (!company_name) {
            companyNameError = "This field is required";
        }
        if (!hiring_budget) {
            hiringBudgetError = "This field is required";
        }
        if (!how_many_hires) {
            howManyHiresError = "This field is required";
        }
        if (!job_title) {
            jobTitleError = "This field is required";
        }
        if (!user_role_id) {
            userRoleError = "This field is required";
        }
        if (!job_working_type) {
            JobWorkTypeError = "This field is required";
        }
        // const errors = {cityError, companyNameError, hiringBudgetError, howManyHiresError, jobTitleError, userRoleError};
        this.setState({
            errors: {
                cityError: cityError,
                companyNameError: companyNameError,
                hiringBudgetError: hiringBudgetError,
                howManyHiresError: howManyHiresError,
                jobTitleError: jobTitleError,
                userRoleError: userRoleError,
                JobWorkTypeError: JobWorkTypeError
            }
        })

        if (cityError || companyNameError || hiringBudgetError || howManyHiresError || jobTitleError || userRoleError | JobWorkTypeError) {
            return;
        }
        const response = await ApiRequest.postRequest('/jobPost', { city_id, company_name, hiring_budget, job_title, job_working_type, user_role_id, how_many_hires, post_lang_id, country_id, post_id: this.state.post_id, always_hiring })
        if (response && response.status === 200) {
            console.log(this.props.personalInfo)
            let country = {};
            if (this.state.countrySelected?.value) {
                country = this.state.countrySelected;
            } else {
                country = {
                    value: this.props.personalInfo?.country?.id,
                    label: this.props.personalInfo?.country?.name,
                }
            }
            localStorage.setItem('citySelected', JSON.stringify(this.state.citySelected));
            localStorage.setItem('countrySelected', JSON.stringify(this.state.countrySelected));
            localStorage.setItem('langSelected', JSON.stringify(this.state.langSelected));
            localStorage.setItem('postData', JSON.stringify(response.data));
            this.props.handler('step_two', true)
        } else {
            toasterAlert('error', 'Something went wrong please try again')
        }

    }

    render() {
        this.getCountryCities(this.props?.personalInfo[0]?.country?.id)
        console.log(this.props)
        return (
            <div className={`row mar-width-0 postBodyWrap ${this.props.className}`}>
                <div className="container">
                    <div className="row mar-width-0 postWrap">
                        <div className="col-md-6 align-self-center pl-50">
                            <h3>Post a Job</h3>
                        </div>
                        <div className="col-md-6 text-center pl-50">
                            <img src={Post1} alt="" />
                        </div>
                    </div>
                    <div className="row mar-width-0 postDetails">
                        <div className="col-md-12">
                            <h5>Let's get start</h5>
                        </div>
                        <form className="w-100 form-wrap" onSubmit={this.handleSubmit}>
                            <div className="col-md-12 mb-3">
                                <div className="form-group mb-0">
                                    <label htmlFor="exampleInputEmail1">Company name for this job *</label>
                                    <input type="text" name="company_name" className="form-control" id="exampleInputEmail1"
                                        value={this.state.company_name}
                                        onChange={this.handleChange}
                                    />
                                    <span className="error">{this.state.errors.companyNameError}</span>

                                </div>
                            </div>
                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">Your role in the hiring process</label>
                                {/* <select className="form-select" aria-label="Default select example" name="user_role_id" value={this.state.user_role_id} onChange={this.handleChange}>
                                    <option selected></option>
                                    <option value="1">One</option>
                                    <option value="2">Two</option>
                                    <option value="3">Three</option>
                                </select> */}
                                {this.hiringRolesList()}
                                <span className="error">{this.state.errors.userRoleError}</span>
                            </div>
                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">Your typical hiring budget</label>
                                {/* <select className="form-select" aria-label="Default select example" name="hiring_budget" value={this.state.hiring_budget} onChange={this.handleChange}>
                                    <option selected></option>
                                    <option value="1">One</option>
                                    <option value="2">Two</option>
                                    <option value="3">Three</option>
                                </select> */}
                                {this.hiringBudgetList()}
                                <span className="error">{this.state.errors.hiringBudgetError}</span>

                            </div>
                            <div className="col-md-12 mb-3">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail1">Job title *</label>
                                    <input type="text" name="job_title" className="form-control" id="exampleInputEmail1" value={this.state.job_title} onChange={this.handleChange}
                                    />
                                    <span className="error">{this.state.errors.jobTitleError}</span>

                                </div>
                            </div>
                            <div className="col-md-12 mb-3">
                                <div className="form-group">
                                    <label htmlFor="exampleInputEmail1">Location *</label>
                                    {/* <input type="number" name="city_id" className="form-control" id="exampleInputEmail1" onChange={this.handleChange}
                                    /> */}
                                    {this.CitiesByCountry()}
                                    <span className="error">{this.state.errors.cityError}</span>

                                </div>
                            </div>
                            <div className="col-md-12 mb-2">
                                {this.countryDetails()}
                            </div>
                            <div className="col-md-12 mb-3">
                                {this.LanguageList()}
                            </div>

                            <div className="col-md-12 mb-2 radio-">
                                <label>
                                    Can this job be performed remotely, meaning primarily from home? If so, we’ll add a “Remote” tag to your post
                                </label>

                                <p className="mt-2">
                                    <input type="radio" id="test1" name="job_working_type" value="1" onChange={this.handleChange} checked={this.state.job_working_type == 1 ?? true} />
                                    <label htmlFor="test1">No</label>
                                </p>
                                <p>
                                    <input type="radio" id="test2" name="job_working_type" value="2" onChange={this.handleChange} checked={this.state.job_working_type == 2 ?? true} />
                                    <label htmlFor="test2">Temporarily due to COVID-19</label>
                                </p>
                                <p>
                                    <input type="radio" id="test3" name="job_working_type" value="3" onChange={this.handleChange} checked={this.state.job_working_type == 3 ?? true} />
                                    <label htmlFor="test3">Yes</label>
                                </p>

                            </div>
                            <div className="col-md-6 mb-2">
                                <label>
                                    How many hires? *
                                </label>
                                <br />
                                <span className="f-f">This helps us match you with the right <br /> number of applicants.</span>
                                <div className="input-plus-minus">
                                    <input type="number" name="how_many_hires" onChange={this.handleChange} value={this.state.how_many_hires} />
                                    <span className="minus-" onClick={() => this.HiresMinus()}>-</span>
                                    <span className="plus-" onClick={() => this.HiresAddUp()}>+</span>

                                </div>
                                <span className="error">{this.state.errors.howManyHiresError}</span>
                            </div>
                            <div className="col-md-12 mb-2">
                                <label className="custom-control fill-checkbox">
                                    <input type="checkbox" className="fill-control-input" name="always_hiring" value={this.state.always_hiring} onChange={this.handleCheckbox} />
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> Always hiring</span>
                                </label>

                            </div>

                            <div className="row mar-width-0 mt-5">
                                <div className="col-md-6">
                                    <Link to="/JobPosting" className="btn btn-back">Back</Link>

                                </div>
                                <div className="col-md-6 text-right">
                                    <button type="submit" className="btn btn-continue">Continue</button>
                                </div>
                            </div>


                        </form>
                    </div>
                </div>
            </div>
        )
    }
}
PostJobTab.propTypes = {
    userInfo: PropTypes.array,
    countries: PropTypes.array,
};

export default PostJobTab;